(window.webpackJsonp=window.webpackJsonp||[]).push([[325],{952:function(n,o){n.exports='\x3c!-- \ntitle: 13-CSS工具\nsort: \n--\x3e \n# CSS工具\n\n## 导航栏\n\n### 竖向\n\n```css\nul {\n    list-style-type: none;\n    margin: 0;\n    padding: 0;\n    width: 200px;\n    background-color: #f1f1f1;\n    border: 1px solid #555;\n}\n\nli a {\n    display: block;\n    /* 将a元素的接触范围映射至框 */\n    color: #000;\n    padding: 8px 16px;\n    text-decoration: none;\n}\n\nli {\n    text-align: center;\n    border-bottom: 1px solid #555;\n}\n\nli:last-child {\n    border-bottom: none;\n}\n\nli a.active {\n    background-color: #4CAF50;\n    color: white;\n}\n\nli a:hover:not(.active) {\n    background-color: #555;\n    color: white;\n}\n```\n\n### 横向\n\n```css\nul {\n    list-style-type: none;\n    margin: 0;\n    padding: 0;\n    overflow: auto;\n    background-color: #333;\n    position: fixed;\n    top: 0;\n    width: 100%;\n}\n\nli {\n    float: left;\n}\n\nli a {\n    display: block;\n    color: white;\n    text-align: center;\n    padding: 14px 16px;\n    text-decoration: none;\n}\n\nli a:hover:not(.active) {\n    background-color: #111;\n}\n\n.active {\n    background-color: #4CAF50;\n}\n```\n\n## 下拉菜单\n\n```html\n<style>\n.dropdown {\n  position: relative;\n  display: inline-block;\n}\n.dropdown-content {\n  display: none;\n  position: absolute;\n  background-color: #f9f9f9;\n  min-width: 160px;\n  /* 阴影 */\n  box-shadow: 0px 8px 16px 0px rgba(0,0,0,0.2);\n  /* 内边距 */\n  padding: 12px 16px;\n}\n.dropdown:hover .dropdown-content {\n  display: block;\n}\n</style>\n\n<div class="dropdown">\n  <span>鼠标移动到我这！</span>\n  <div class="dropdown-content">\n    <p>fzf</p>\n    <p>39.106.106.202</p>\n  </div>\n</div>\n```\n\n```html\n\n<style>\n/* 按钮样式 */\n.dropbtn {\n    background-color: #4CAF50;\n    color: white;\n    padding: 16px;\n    font-size: 16px;\n    border: none;\n    cursor: pointer;\n}\n\n.dropdown {\n    position: relative;\n    display: inline-block;\n}\n\n.dropdown-content {\n    display: none;\n    position: absolute;\n    background-color: #f9f9f9;\n    min-width: 160px;\n    box-shadow: 0px 8px 16px 0px rgba(0,0,0,0.2);\n}\n\n.dropdown-content a {\n    color: black;\n    padding: 12px 16px;\n    text-decoration: none;\n    display: block;\n}\n\n.dropdown-content a:hover {background-color: #f1f1f1}\n\n.dropdown:hover .dropdown-content {\n    display: block;\n}\n\n.dropdown:hover .dropbtn {\n    background-color: #3e8e41;\n}\n</style>\n\n<div class="dropdown">\n  <button class="dropbtn">下拉菜单</button>\n  <div class="dropdown-content">\n    <a href="//www.runoob.com">菜鸟教程 1</a>\n    <a href="//www.runoob.com">菜鸟教程 2</a>\n    <a href="//www.runoob.com">菜鸟教程 3</a>\n  </div>\n</div>\n```\n\n'}}]);